/* ─── UTILS ─── */
function useReveal() {
  const ref = useRef(null);
  const inView = useInView(ref, { once: true, margin: "-60px" });
  return [ref, inView];
}

const fu = (d = 0) => ({
  initial: { opacity: 0, y: 40 },
  animate: { opacity: 1, y: 0 },
  transition: { duration: 0.75, delay: d, ease: [0.16, 1, 0.3, 1] },
});

const Label = ({ children }) => (
  <span className="inline-flex items-center gap-2 text-xs font-bold tracking-[0.2em] uppercase mb-4 px-3 py-1.5 rounded-full"
    style={{ color: C.primary, border: `1px solid ${C.primary}40`, background: `${C.primary}12` }}>
    <span className="w-1.5 h-1.5 rounded-full" style={{ background: C.primary }} />
    {children}
  </span>
);

/* ─── LOADER ─── */
function Loader({ onDone }) {
  useEffect(() => { const t = setTimeout(onDone, 2000); return () => clearTimeout(t); }, [onDone]);
  return (
    <motion.div exit={{ opacity: 0 }} transition={{ duration: 0.5 }}
      className="fixed inset-0 z-[200] flex items-center justify-center flex-col gap-8"
      style={{ background: C.bg }}>
      <motion.div initial={{ scale: 0.7, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} transition={{ duration: 0.5 }}
        className="relative flex items-center justify-center">
        <motion.div className="absolute w-32 h-32 rounded-full blur-3xl"
          animate={{ scale: [1,1.3,1], opacity: [0.3,0.7,0.3] }} transition={{ repeat: Infinity, duration: 2 }}
          style={{ background: `linear-gradient(135deg, ${C.primary}, ${C.cyan})` }} />
        <div className="relative w-24 h-24 rounded-full overflow-hidden border-2"
          style={{ borderColor: `${C.primary}60` }}>
          <img src={PROFILE_PHOTO} alt="Misba" className="w-full h-full object-cover object-top" />
        </div>
      </motion.div>
      <motion.div initial={{ opacity: 0, y: 12 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.3 }}
        className="text-3xl font-black tracking-tight"
        style={{ fontFamily: "Poppins,sans-serif", background: `linear-gradient(135deg, #fff, ${C.primary}, ${C.cyan})`, WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent" }}>
        Misba AMF
      </motion.div>
      <div className="flex gap-1.5">
        {[0,1,2,3,4].map(i => (
          <motion.div key={i} className="w-1.5 h-1.5 rounded-full" style={{ background: C.primary }}
            animate={{ scaleY: [1,3,1], opacity: [0.3,1,0.3] }}
            transition={{ repeat: Infinity, duration: 1, delay: i * 0.12 }} />
        ))}
      </div>
    </motion.div>
  );
}

/* ─── NAVBAR ─── */
function Navbar({ active }) {
  const [scrolled, setScrolled] = useState(false);
  const [open, setOpen] = useState(false);
  useEffect(() => {
    const fn = () => setScrolled(window.scrollY > 50);
    window.addEventListener("scroll", fn);
    return () => window.removeEventListener("scroll", fn);
  }, []);
  return (
    <motion.nav initial={{ y: -80, opacity: 0 }} animate={{ y: 0, opacity: 1 }}
      transition={{ duration: 0.7, ease: [0.16,1,0.3,1] }}
      className="fixed top-0 left-0 right-0 z-50 transition-all duration-500"
      style={scrolled ? { background: "rgba(8,11,20,0.88)", backdropFilter: "blur(24px)", borderBottom: `1px solid ${C.primary}20` } : {}}>
      <div className="max-w-6xl mx-auto px-6 py-4 flex items-center justify-between">
        <motion.div whileHover={{ scale: 1.05 }} onClick={() => {
            const el = document.getElementById("main-scroll");
            if(el) el.scrollTo({ top: 0, behavior: "smooth" });
          }}
          className="flex items-center gap-3 cursor-pointer">
          <div className="w-9 h-9 rounded-full overflow-hidden border-2" style={{ borderColor: `${C.primary}60`, boxShadow: `0 0 12px ${C.primary}40` }}>
            <img src={PROFILE_PHOTO} alt="M" className="w-full h-full object-cover object-top" />
          </div>
          <span className="text-lg font-black tracking-tight" style={{ fontFamily:"Poppins,sans-serif", background: `linear-gradient(90deg, ${C.primary}, ${C.cyan})`, WebkitBackgroundClip:"text", WebkitTextFillColor:"transparent" }}>
            M·AMF
          </span>
        </motion.div>
        <div className="hidden md:flex items-center gap-7">
          {NAV_LINKS.map(link => (
            <a key={link} href={`#${link.toLowerCase()}`}
              onClick={e=>{e.preventDefault();const t=document.getElementById(link.toLowerCase());const s=document.getElementById("main-scroll");if(t&&s)s.scrollTo({top:t.offsetTop,behavior:"smooth"});}}
              className="text-sm font-medium transition-all duration-200 hover:text-white relative group"
              style={{ color: active === link.toLowerCase() ? "#fff" : C.muted, fontFamily:"Poppins,sans-serif" }}>
              {link}
              <span className="absolute -bottom-0.5 left-0 h-px w-0 group-hover:w-full transition-all duration-300"
                style={{ background: `linear-gradient(90deg, ${C.primary}, ${C.cyan})` }} />
              {active === link.toLowerCase() && (
                <span className="absolute -bottom-0.5 left-0 h-px w-full" style={{ background: `linear-gradient(90deg, ${C.primary}, ${C.cyan})` }} />
              )}
            </a>
          ))}
          <motion.a href="#contact" whileHover={{ scale: 1.05, boxShadow: `0 0 28px ${C.primary}50` }} whileTap={{ scale: 0.97 }}
            className="px-5 py-2.5 rounded-full text-sm font-bold text-white"
            style={{ background: `linear-gradient(135deg, ${C.primary}, ${C.violet})`, fontFamily:"Poppins,sans-serif" }}>
            Hire Me
          </motion.a>
        </div>
        <button onClick={() => setOpen(!open)} className="md:hidden p-1">
          {[0,1,2].map(i => (
            <span key={i} className="block w-6 h-px my-1.5 transition-all" style={{ background: C.muted,
              transform: open && i===0 ? "rotate(45deg) translate(3px,5px)" : open && i===2 ? "rotate(-45deg) translate(3px,-5px)" : "none",
              opacity: open && i===1 ? 0 : 1 }} />
          ))}
        </button>
      </div>
      <AnimatePresence>
        {open && (
          <motion.div initial={{ opacity:0,height:0 }} animate={{ opacity:1,height:"auto" }} exit={{ opacity:0,height:0 }}
            className="md:hidden px-6 pb-5" style={{ background: "rgba(8,11,20,0.97)", borderBottom: `1px solid ${C.primary}15` }}>
            {NAV_LINKS.map(link => (
              <a key={link} href={`#${link.toLowerCase()}`} onClick={e=>{e.preventDefault();setOpen(false);const t=document.getElementById(link.toLowerCase());const s=document.getElementById("main-scroll");if(t&&s)s.scrollTo({top:t.offsetTop,behavior:"smooth"});}}
                className="block py-3.5 text-sm font-medium border-b" style={{ color: C.muted, borderColor: "rgba(255,255,255,0.05)", fontFamily:"Poppins,sans-serif" }}>
                {link}
              </a>
            ))}
          </motion.div>
        )}
      </AnimatePresence>
    </motion.nav>
  );
}

